k A B |year=[[2000]]|month=Sep. |title=Negative regulation of the serine/threonine kinase B-Raf by Akt |journal=J. Biol. Chem. |volume=275 |issue=35 |pages=27354–9 | issn=0021-9258| pmid=10869359 |doi=10.1074/jbc.M004371200 |bibcode= |oclc= |laysummary= |laysource= |laydate= |quote= }}</ref> and [[HRAS]].<ref name=pmid9154803>{{cite journal | quotes = yes |last=Stang |first=S |authorlink= |coauthors=Bottorff D, Stone JC |year=1997 |month=Jun |title=Interaction of activated Ras with Raf-1 alone may be sufficient for transformation of rat2 cells |journal=Mol Cell Biol |volume=17 |issue=6 |pages=3047–55 |issn=0270-7306 |pmid = 9154803 | bibcode = | oclc =| laysummary = | laysource = | laydate = | quote = }}</ref><ref name=pmid7706312>{{cite journal | quotes = yes |last=Reuter |first=CW |authorlink= |coauthors=Catling AD, Jelinek T, Weber MJ |year=1995 |month=Mar |title=Biochemical analysis of MEK activation in NIH3T3 fibroblasts. Identification of B-Raf and other activators |journal=J Biol Chem |volume=270 |issue=13 |pages=7644–55 |issn = 0021-9258|  bibcode = | oclc = |pmid=7706312| laysummary = | laysource = | laydate = | quote = }}</ref>  

